import { useState } from "react";
import GlobalStyle from "./assets/styles/GlobalStyle";

// ─── PAGES ────────────────────────────────────────────────────────────────────
import PublicWebsite from "./pages/Public";
import LoginPage from "./pages/Auth/LoginPage";
import StudentDashboard from "./pages/Student";
import AdminDashboard from "./pages/Admin";
import { TeacherDashboard, ParentDashboard } from "./pages/TeacherParent";

// ─── APP ──────────────────────────────────────────────────────────────────────
// View flow:
//   public  →  login  →  student / teacher / admin / parent
//   Any dashboard  →  login (logout)
//   login  →  public (back button)

export default function App() {
  const [view, setView] = useState("public");
  // "public" | "login" | "student" | "teacher" | "admin" | "parent"

  const handleLogin = (role) => setView(role);
  const handleLogout = () => setView("login");

  return (
    <>
      <GlobalStyle />
      {view === "public"  && <PublicWebsite   onGoToLogin={() => setView("login")} />}
      {view === "login"   && <LoginPage        onLogin={handleLogin} onBack={() => setView("public")} />}
      {view === "student" && <StudentDashboard onLogout={handleLogout} />}
      {view === "teacher" && <TeacherDashboard onLogout={handleLogout} />}
      {view === "admin"   && <AdminDashboard   onLogout={handleLogout} />}
      {view === "parent"  && <ParentDashboard  onLogout={handleLogout} />}
    </>
  );
}
